  `demand_id` bigint(20) NULL DEFAULT NULL COMMENT '需求ID',
  `order_id` bigint(20) NULL DEFAULT NULL COMMENT '订单ID',
  `sender_id` bigint(20) NOT NULL COMMENT '发送人ID',
  `receiver_id` bigint(20) NOT NULL COMMENT '接收人ID',
  `msg_type` tinyint(4) NOT NULL COMMENT '1文本 2图片 3文件 4系统',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '消息内容',
  `file_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '文件地址',
  `extra_json` json NULL COMMENT '扩展字段',
  `read_status` tinyint(4) NOT NULL DEFAULT 0 COMMENT '0未读 1已读',
  `status` tinyint(4) NOT NULL DEFAULT 1 COMMENT '1正常 2撤回 3删除',
  `read_at` datetime(0) NULL DEFAULT NULL COMMENT '已读时间',
  `created_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '创建时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_order_time`(`order_id`, `created_at`) USING BTREE,
  INDEX `idx_demand_time`(`demand_id`, `created_at`) USING BTREE,
  INDEX `idx_receiver_unread`(`receiver_id`, `read_status`, `created_at`) USING BTREE,
  INDEX `fk_chat_message_sender_id`(`sender_id`) USING BTREE,
  CONSTRAINT `fk_chat_message_demand_id` FOREIGN KEY (`demand_id`) REFERENCES `demand` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_chat_message_order_id` FOREIGN KEY (`order_id`) REFERENCES `orders` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_chat_message_receiver_id` FOREIGN KEY (`receiver_id`) REFERENCES `user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_chat_message_sender_id` FOREIGN KEY (`sender_id`) REFERENCES `user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '聊天消息表' ROW_FORMAT = Dynamic;

