DROP TABLE IF EXISTS `demand`;
CREATE TABLE `demand`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `demand_no` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '需求编号',
  `publisher_id` bigint(20) NOT NULL COMMENT '发布人ID',
  `title` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '需求标题',
  `summary` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '摘要',
  `detail` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '详细描述',
  `category_id` bigint(20) NULL DEFAULT NULL COMMENT '分类ID',
  `category` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '分类名称',
  `budget_min` decimal(12, 2) NOT NULL COMMENT '预算下限',
  `budget_max` decimal(12, 2) NOT NULL COMMENT '预算上限',
  `expected_days` int(11) NOT NULL COMMENT '预计工期',
  `delivery_type` tinyint(4) NOT NULL DEFAULT 1 COMMENT '1单阶段 2多阶段',
  `attachments_json` json NULL COMMENT '附件JSON',
  `contact_note` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '补充说明',
  `quote_count` int(11) NOT NULL DEFAULT 0 COMMENT '报价数',
  `review_status` tinyint(4) NOT NULL DEFAULT 0 COMMENT '0待审 1通过 2驳回',
  `status` tinyint(4) NOT NULL DEFAULT 0 COMMENT '0草稿 1待审核 2待报价 3报价中 4已选开发者 5进行中 6已完成 7已取消 8已驳回',
  `publish_at` datetime(0) NULL DEFAULT NULL COMMENT '发布时间',
  `closed_at` datetime(0) NULL DEFAULT NULL COMMENT '关闭时间',
  `reject_reason` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '驳回原因',
  `version` int(11) NOT NULL DEFAULT 0 COMMENT '乐观锁版本号',
  `created_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '创建时间',
  `updated_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) ON UPDATE CURRENT_TIMESTAMP(0) COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_demand_no`(`demand_no`) USING BTREE,
  INDEX `idx_publisher_status`(`publisher_id`, `status`) USING BTREE,
  INDEX `idx_review_status`(`review_status`, `status`) USING BTREE,
  INDEX `idx_market`(`status`, `category`, `created_at`) USING BTREE,
  CONSTRAINT `fk_demand_publisher_id` FOREIGN KEY (`publisher_id`) REFERENCES `user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '需求表' ROW_FORMAT = Dynamic;

