-- Table structure for dispute
-- ----------------------------
DROP TABLE IF EXISTS `dispute`;
CREATE TABLE `dispute`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `dispute_no` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '纠纷编号',
  `order_id` bigint(20) NOT NULL COMMENT '订单ID',
  `initiator_id` bigint(20) NOT NULL COMMENT '发起人ID',
  `respondent_id` bigint(20) NOT NULL COMMENT '被申诉人ID',
  `admin_id` bigint(20) NULL DEFAULT NULL COMMENT '处理管理员ID',
  `dispute_type` tinyint(4) NOT NULL COMMENT '1延期 2质量不达标 3未交付 4付款争议 5违规沟通',
  `reason` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '纠纷原因',
  `detail` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '详细说明',
  `evidence_json` json NULL COMMENT '证据JSON',
  `freeze_amount` decimal(12, 2) NOT NULL DEFAULT 0.00 COMMENT '冻结金额',
  `status` tinyint(4) NOT NULL DEFAULT 0 COMMENT '0待受理 1处理中 2待举证 3已裁决 4已驳回 5已关闭',
  `result_type` tinyint(4) NOT NULL DEFAULT 0 COMMENT '0无 1退款给甲方 2放款给乙方 3部分分账 4继续履约',
  `resolution_note` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '处理说明',
  `resolved_at` datetime(0) NULL DEFAULT NULL COMMENT '裁决时间',
  `closed_at` datetime(0) NULL DEFAULT NULL COMMENT '关闭时间',
  `version` int(11) NOT NULL DEFAULT 0 COMMENT '乐观锁版本号',
  `created_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '创建时间',
  `updated_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) ON UPDATE CURRENT_TIMESTAMP(0) COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_dispute_no`(`dispute_no`) USING BTREE,
  INDEX `idx_order_status`(`order_id`, `status`) USING BTREE,
  INDEX `idx_admin_status`(`admin_id`, `status`) USING BTREE,
  INDEX `idx_initiator_status`(`initiator_id`, `status`) USING BTREE,
  INDEX `fk_dispute_respondent_id`(`respondent_id`) USING BTREE,
  CONSTRAINT `fk_dispute_admin_id` FOREIGN KEY (`admin_id`) REFERENCES `admin_user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_dispute_initiator_id` FOREIGN KEY (`initiator_id`) REFERENCES `user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_dispute_order_id` FOREIGN KEY (`order_id`) REFERENCES `orders` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_dispute_respondent_id` FOREIGN KEY (`respondent_id`) REFERENCES `user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '纠纷表' ROW_FORMAT = Dynamic;

