-- ----------------------------
-- Table structure for order_stage
-- ----------------------------
DROP TABLE IF EXISTS `order_stage`;
CREATE TABLE `order_stage`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `order_id` bigint(20) NOT NULL COMMENT '订单ID',
  `stage_no` int(11) NOT NULL COMMENT '阶段序号',
  `stage_name` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '阶段名称',
  `stage_desc` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '阶段说明',
  `stage_amount` decimal(12, 2) NOT NULL COMMENT '阶段金额',
  `plan_start_at` datetime(0) NULL DEFAULT NULL COMMENT '计划开始时间',
  `plan_end_at` datetime(0) NULL DEFAULT NULL COMMENT '计划结束时间',
  `submit_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '提交说明',
  `deliverable_json` json NULL COMMENT '交付物JSON',
  `status` tinyint(4) NOT NULL DEFAULT 0 COMMENT '0待开始 1进行中 2已提交 3已验收 4已打回 5已取消',
  `actual_start_at` datetime(0) NULL DEFAULT NULL COMMENT '实际开始时间',
  `actual_submit_at` datetime(0) NULL DEFAULT NULL COMMENT '实际提交时间',
  `actual_accept_at` datetime(0) NULL DEFAULT NULL COMMENT '实际验收时间',
  `reject_reason` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '打回原因',
  `version` int(11) NOT NULL DEFAULT 0 COMMENT '乐观锁版本号',
  `created_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '创建时间',
  `updated_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) ON UPDATE CURRENT_TIMESTAMP(0) COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_order_stage`(`order_id`, `stage_no`) USING BTREE,
  INDEX `idx_order_status`(`order_id`, `status`) USING BTREE,
  CONSTRAINT `fk_order_stage_order_id` FOREIGN KEY (`order_id`) REFERENCES `orders` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '订单阶段表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of order_stage
-- ----------------------------

-- ----------------------------
-- Table structure for orders
-- ----------------------------
DROP TABLE IF EXISTS `orders`;
CREATE TABLE `orders`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `order_no` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '订单编号',
  `demand_id` bigint(20) NOT NULL COMMENT '需求ID',
  `quote_id` bigint(20) NULL DEFAULT NULL COMMENT '选中的报价ID',
  `client_id` bigint(20) NOT NULL COMMENT '甲方用户ID',
  `developer_id` bigint(20) NULL DEFAULT NULL COMMENT '乙方开发者ID',
  `order_title` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '订单标题',
  `amount_total` decimal(12, 2) NOT NULL DEFAULT 0.00 COMMENT '订单总金额',
  `escrow_amount` decimal(12, 2) NOT NULL DEFAULT 0.00 COMMENT '托管金额',
  `platform_fee` decimal(12, 2) NOT NULL DEFAULT 0.00 COMMENT '平台服务费',
  `pay_status` tinyint(4) NOT NULL DEFAULT 0 COMMENT '0未支付 1已托管 2已放款 3已退款 4已分账',
  `status` tinyint(4) NOT NULL DEFAULT 0 COMMENT '0WAIT_QUOTE 1QUOTED 2PAID 3IN_PROGRESS 4WAIT_ACCEPT 5COMPLETED 6CANCELLED 7DISPUTE',
  `current_stage_no` int(11) NOT NULL DEFAULT 0 COMMENT '当前阶段号',
  `progress_percent` int(11) NOT NULL DEFAULT 0 COMMENT '订单进度',
  `selected_at` datetime(0) NULL DEFAULT NULL COMMENT '选中报价时间',
  `paid_at` datetime(0) NULL DEFAULT NULL COMMENT '托管支付时间',
  `started_at` datetime(0) NULL DEFAULT NULL COMMENT '开始开发时间',
  `submitted_at` datetime(0) NULL DEFAULT NULL COMMENT '提交交付时间',
  `accepted_at` datetime(0) NULL DEFAULT NULL COMMENT '验收通过时间',
  `completed_at` datetime(0) NULL DEFAULT NULL COMMENT '完成时间',
  `cancelled_at` datetime(0) NULL DEFAULT NULL COMMENT '取消时间',
  `cancel_reason` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '取消原因',
  `version` int(11) NOT NULL DEFAULT 0 COMMENT '乐观锁版本号',
  `created_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '创建时间',
  `updated_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) ON UPDATE CURRENT_TIMESTAMP(0) COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_order_no`(`order_no`) USING BTREE,
  UNIQUE INDEX `uk_demand_id`(`demand_id`) USING BTREE,
  INDEX `idx_client_status`(`client_id`, `status`, `updated_at`) USING BTREE,
  INDEX `idx_developer_status`(`developer_id`, `status`, `updated_at`) USING BTREE,
  INDEX `idx_status_time`(`status`, `updated_at`) USING BTREE,
  INDEX `fk_orders_quote_id`(`quote_id`) USING BTREE,
  CONSTRAINT `fk_orders_client_id` FOREIGN KEY (`client_id`) REFERENCES `user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_orders_demand_id` FOREIGN KEY (`demand_id`) REFERENCES `demand` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_orders_developer_id` FOREIGN KEY (`developer_id`) REFERENCES `user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_orders_quote_id` FOREIGN KEY (`quote_id`) REFERENCES `quote` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '订单表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of orders
-- ----------------------------

-- ----------------------------
-- Table structure for quote
-- ----------------------------
DROP TABLE IF EXISTS `quote`;
CREATE TABLE `quote`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `quote_no` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '报价编号',
  `demand_id` bigint(20) NOT NULL COMMENT '需求ID',
  `developer_id` bigint(20) NOT NULL COMMENT '开发者ID',
  `price_total` decimal(12, 2) NOT NULL COMMENT '总报价',
  `estimated_days` int(11) NOT NULL COMMENT '预计开发天数',
  `tech_solution` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '技术方案',
  `delivery_desc` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '交付说明',
  `attach_json` json NULL COMMENT '附件JSON',
  `valid_until` datetime(0) NULL DEFAULT NULL COMMENT '报价有效期',
  `status` tinyint(4) NOT NULL DEFAULT 0 COMMENT '0有效 1已中标 2已落选 3已撤回 4已过期',
  `selected_at` datetime(0) NULL DEFAULT NULL COMMENT '中标时间',
  `version` int(11) NOT NULL DEFAULT 0 COMMENT '乐观锁版本号',
  `created_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '创建时间',
  `updated_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) ON UPDATE CURRENT_TIMESTAMP(0) COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_quote_no`(`quote_no`) USING BTREE,
  UNIQUE INDEX `uk_demand_dev`(`demand_id`, `developer_id`) USING BTREE,
  INDEX `idx_demand_status`(`demand_id`, `status`, `created_at`) USING BTREE,
  INDEX `idx_dev_status`(`developer_id`, `status`, `created_at`) USING BTREE,
  CONSTRAINT `fk_quote_demand_id` FOREIGN KEY (`demand_id`) REFERENCES `demand` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_quote_developer_id` FOREIGN KEY (`developer_id`) REFERENCES `user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '报价表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of quote
-- ----------------------------

