-- ----------------------------
-- Table structure for user
-- ----------------------------
DROP TABLE IF EXISTS `user`;
CREATE TABLE `user`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_no` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '用户编号',
  `openid` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '微信公众号openid',
  `phone` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '手机号',
  `email` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '邮箱',
  `password_hash` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '密码哈希',
  `nickname` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '昵称',
  `avatar_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '头像',
  `user_type` tinyint(4) NOT NULL COMMENT '1普通用户 2开发者(兼容) 3双角色(兼容)',
  `real_name` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '真实姓名',
  `id_card_no` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '身份证号码',
  `id_verify_status` tinyint(4) NOT NULL DEFAULT 0 COMMENT '0未认证 1审核中 2已通过 3已拒绝',
  `developer_status` tinyint(4) NOT NULL DEFAULT 0 COMMENT '0未申请 1审核中 2已通过 3已拒绝 4已封禁',
  `skill_tags` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '技能标签，逗号分隔',
  `developer_role_type` tinyint(4) NOT NULL DEFAULT 0 COMMENT '0普通用户 1程序开发 2文档撰写 3都能做',
  `id_card_front_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '身份证正面图片',
  `id_card_back_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '身份证反面图片',
  `selfie_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '手持身份证照片',
  `skill_audit_status` tinyint(4) NOT NULL DEFAULT 0 COMMENT '0未提交 1审核中 2已通过 3已拒绝',
  `skill_audit_reason` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '审核备注',
  `developer_skill_tag_ids` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '开发者技术栈ID列表',
  `intro` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '个人简介',
  `rating` decimal(3, 2) NOT NULL DEFAULT 5.00 COMMENT '评分',
  `completed_order_count` int(11) NOT NULL DEFAULT 0 COMMENT '完成订单数',
  `status` tinyint(4) NOT NULL DEFAULT 1 COMMENT '1正常 2封禁 3注销',
  `ban_reason` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '灏佺鍘熷洜',
  `ban_expires_at` datetime(0) NULL DEFAULT NULL COMMENT '灏佺鍒版湡鏃堕棿',
  `last_login_at` datetime(0) NULL DEFAULT NULL COMMENT '最后登录时间',
  `version` int(11) NOT NULL DEFAULT 0 COMMENT '乐观锁版本号',
  `created_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '创建时间',
  `updated_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) ON UPDATE CURRENT_TIMESTAMP(0) COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_no`(`user_no`) USING BTREE,
  UNIQUE INDEX `uk_openid`(`openid`) USING BTREE,
  UNIQUE INDEX `uk_phone`(`phone`) USING BTREE,
  UNIQUE INDEX `uk_email`(`email`) USING BTREE,
  INDEX `idx_user_type_status`(`user_type`, `status`) USING BTREE,
  INDEX `idx_dev_status`(`developer_status`, `status`) USING BTREE,
  INDEX `idx_ban_expire`(`status`, `ban_expires_at`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '平台用户表' ROW_FORMAT = Dynamic;

