-- Table structure for user_inbox_message
-- ----------------------------
DROP TABLE IF EXISTS `user_inbox_message`;
CREATE TABLE `user_inbox_message`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_id` bigint(20) NOT NULL COMMENT '接收用户ID',
  `admin_id` bigint(20) NULL DEFAULT NULL COMMENT '发送管理员ID',
  `title` varchar(120) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '消息标题',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '消息内容',
  `action_url` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT '站内通知跳转地址',
  `read_status` tinyint(4) NOT NULL DEFAULT 0 COMMENT '0未读 1已读',
  `read_at` datetime(0) NULL DEFAULT NULL COMMENT '已读时间',
  `status` tinyint(4) NOT NULL DEFAULT 1 COMMENT '1正常 2删除',
  `created_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '创建时间',
  `updated_at` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) ON UPDATE CURRENT_TIMESTAMP(0) COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_read_time`(`user_id`, `read_status`, `created_at`) USING BTREE,
  INDEX `idx_admin_time`(`admin_id`, `created_at`) USING BTREE,
  CONSTRAINT `fk_user_inbox_message_admin_id` FOREIGN KEY (`admin_id`) REFERENCES `admin_user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `fk_user_inbox_message_user_id` FOREIGN KEY (`user_id`) REFERENCES `user` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '用户站内信表' ROW_FORMAT = Dynamic;

